import React, { useState } from 'react';

const gold = '#D4AF37';
const terracotta = '#C04000';

const Menu = () => {
  // This state handles the "Customize" slide-up panel
  const [showCustomModal, setShowCustomModal] = useState(false);

  return (
    <div style={{ padding: '0 20px', marginTop: '-10px' }}>
      
      {/* --- THE SIGNATURE GRAND PLATTER (THE 200K STAR) --- */}
      <div style={{ 
        width: '100%', 
        backgroundColor: '#111', 
        borderRadius: '15px', 
        marginBottom: '25px',
        border: `1px solid ${terracotta}44`,
        padding: '20px',
        boxSizing: 'border-box'
      }}>
        <h2 style={{ fontSize: '1.1rem', color: '#fff', margin: '0 0 8px 0', letterSpacing: '1px' }}>
          THE ÀMÍ SIGNATURE GRAND PLATTER
        </h2>
        
        <p style={{ fontSize: '0.75rem', color: '#888', margin: '0 0 15px 0', lineHeight: '1.5' }}>
          Handcrafted for your finest guests of 60 and above. A bespoke curation designed for elite gatherings.
        </p>
        
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <span style={{ fontSize: '0.6rem', color: terracotta, display: 'block', fontWeight: 'bold' }}>STARTING AT</span>
            <span style={{ fontSize: '1.1rem', fontWeight: 'bold', color: gold }}>₦200,000</span>
          </div>
          <button 
            onClick={() => setShowCustomModal(true)}
            style={{ 
              backgroundColor: terracotta, color: '#fff', border: 'none', 
              padding: '10px 20px', borderRadius: '8px', fontWeight: 'bold', fontSize: '0.7rem' 
            }}>
            CUSTOMIZE
          </button>
        </div>
      </div>

      {/* --- REGULAR DAILY ITEMS --- */}
      <h3 style={{ fontSize: '0.7rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '15px' }}>
        Daily Platters
      </h3>
      
      <div style={{ display: 'flex', backgroundColor: '#111', borderRadius: '12px', marginBottom: '10px', padding: '12px', alignItems: 'center' }}>
        <div style={{ width: '50px', height: '50px', backgroundColor: '#000', borderRadius: '8px', marginRight: '15px' }}></div>
        <div style={{ flex: 1 }}>
          <h4 style={{ fontSize: '0.85rem', margin: '0', color: '#fff' }}>The Executive Box</h4>
          <div style={{ fontSize: '0.9rem', fontWeight: 'bold', color: gold }}>₦15,000</div>
        </div>
        <button style={{ backgroundColor: '#222', color: '#fff', border: 'none', borderRadius: '20px', padding: '6px 14px', fontSize: '0.65rem' }}>ADD</button>
      </div>

      {/* --- THE CUSTOMIZE PANEL (POPS UP WHEN CLICKED) --- */}
      {showCustomModal && (
        <div style={{ 
          position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', 
          backgroundColor: 'rgba(0,0,0,0.85)', zIndex: 1000, display: 'flex', alignItems: 'flex-end' 
        }}>
          <div style={{ 
            width: '100%', backgroundColor: '#161616', borderTopLeftRadius: '25px', borderTopRightRadius: '25px', 
            padding: '30px 20px', boxSizing: 'border-box' 
          }}>
            <h3 style={{ color: gold, margin: '0 0 10px 0', fontSize: '1.1rem' }}>Tailor Your Event</h3>
            <p style={{ color: '#888', fontSize: '0.7rem', marginBottom: '15px' }}>Tell us more about your 60+ guests and preferences.</p>
            <textarea 
              placeholder="Flavor preferences, date, location..." 
              style={{ width: '100%', height: '100px', backgroundColor: '#000', color: '#fff', borderRadius: '10px', padding: '10px', border: '1px solid #333', fontSize: '0.8rem' }} 
            />
            <button 
              onClick={() => setShowCustomModal(false)} 
              style={{ width: '100%', marginTop: '15px', padding: '15px', backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '10px', fontWeight: 'bold' }}>
              REQUEST QUOTE
            </button>
          </div>
        </div>
      )}

    </div>
  );
};

export default Menu;
